INSERT INTO `oc_information_description` (`information_id`, `language_id`, `title`, `description`) VALUES
(4,	1,	'О нас',	'&lt;p&gt;\r\n	О нас&lt;/p&gt;\r\n'),
(6,	1,	'Вакансии',	'&lt;div style=&quot;font-size: 12px; background-color: rgb(255, 255, 255); &quot;&gt;\r\n	&lt;p style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; &quot;&gt;\r\n		&lt;span class=&quot;Apple-style-span&quot; style=&quot;border-collapse: collapse; color: rgb(60, 60, 60); font-family: Tahoma; font-size: 18px; &quot;&gt;Водитель - курьер&amp;nbsp;&lt;span class=&quot;text-red&quot; style=&quot;color: rgb(204, 0, 0) !important; &quot;&gt;(1000 РУБ за смену + бензин)&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;\r\n	&lt;p style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; &quot;&gt;\r\n		&amp;nbsp;&lt;/p&gt;\r\n	&lt;p style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; &quot;&gt;\r\n		&lt;span class=&quot;Apple-style-span&quot; style=&quot;border-collapse: collapse; color: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;&lt;strong&gt;&lt;strong&gt;Требования:&lt;/strong&gt;&lt;/strong&gt;&lt;br /&gt;\r\n		&lt;/span&gt;&lt;/p&gt;\r\n	&lt;ul style=&quot;margin-top: 10px; margin-right: 10px; margin-bottom: 10px; margin-left: 10px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 30px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; &quot;&gt;\r\n		&lt;li style=&quot;margin-top: 0px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 0px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; list-style-type: disc; &quot;&gt;\r\n			гражданство РФ&lt;/li&gt;\r\n		&lt;li style=&quot;margin-top: 0px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 0px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; list-style-type: disc; &quot;&gt;\r\n			&lt;span class=&quot;Apple-style-span&quot; style=&quot;color: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;наличие автомобиля&amp;nbsp;(работа на личном автотранспорте)&lt;/span&gt;&lt;/li&gt;\r\n	&lt;/ul&gt;\r\n	&lt;p style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; &quot;&gt;\r\n		&lt;strong&gt;&lt;strong&gt;Обязанности:&lt;/strong&gt;&lt;/strong&gt;&lt;/p&gt;\r\n	&lt;p style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; &quot;&gt;\r\n		&amp;nbsp;&lt;/p&gt;\r\n	&lt;ul style=&quot;margin-top: 10px; margin-right: 10px; margin-bottom: 10px; margin-left: 10px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 30px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; &quot;&gt;\r\n		&lt;li style=&quot;margin-top: 0px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 0px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; list-style-type: disc; &quot;&gt;\r\n			&lt;span class=&quot;Apple-style-span&quot; style=&