INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES
(58,	42,	0,	'Дмитрий',	'Отличный товар',	5,	1,	'2011-02-25 07:36:47',	'0000-00-00 00:00:00'),
(59,	42,	0,	'Александр',	'Пользуюсь с удовольствием',	5,	1,	'2011-02-25 07:36:19',	'0000-00-00 00:00:00'),
(60,	47,	0,	'Михаил',	'Товар очень понравился, быстро доставили',	5,	1,	'2011-03-11 13:32:43',	'0000-00-00 00:00:00'),
(61,	42,	0,	'Наталья',	'вчера заказывала эти роллы - очень вкусные! и доставили их всего минут за 30-40. Буду заказывать еще =)',	5,	1,	'2011-04-10 09:05:02',	'0000-00-00 00:00:00'),
(91,	87,	0,	'Георгий',	'Заказывал уже два раза! Из всех, что привозили по телефону, эти однозначно занимают первое место. Да и по сравнению с тем, что подают в большинстве ресторанов, евросуши сильно выигрывают! очень вкусно, очень качественно - молодцы!',	5,	1,	'2011-12-31 01:43:14',	'0000-00-00 00:00:00'),
(63,	106,	0,	'Андрей',	'Весьма необычно, но очень вкусно! Ни где такого не пробовал.',	5,	1,	'2011-02-26 05:17:39',	'0000-00-00 00:00:00'),
(64,	90,	0,	'Ксения',	'В наборе много  ролов и сушиков, их хватит что бы полакомиться большой компании или просто любителям вкусненького!!! Очень вкусно =))))',	5,	1,	'2011-04-10 09:05:29',	'0000-00-00 00:00:00'),
(65,	89,	0,	'Анна',	'Это мои самые любимые!!!Спасибо большое - Очень сытно, вкусно и просто божественное сочетание индегриенов!!!!',	5,	1,	'2011-04-10 09:05:49',	'0000-00-00 00:00:00'),
(66,	56,	0,	'Регина',	'Спасибо вам!!!!была приятна удивленна, очень понравились запеченные роллы с крабом, вкус изумительный и краб действительно настоящий!!!! ',	5,	1,	'2011-04-04 11:09:07',	'0000-00-00 00:00:00'),
(67,	68,	0,	'Ксения',	'Вкуснятина, пальчики оближешь!!!!!',	5,	1,	'2011-04-04 11:08:10',	'0000-00-00 00:00:00'),
(68,	35,	0,	'Антон',	'Такой вкусной филадельфии я еще не пробовал!!!!Рекомендую =)',	5,	1,	'2011-04-04 11:07:54',	'0000-00-00 00:00:00'),
(83,	89,	0,	'Виолетта',	'Это наши одни из самых любимых с мужем!М-м-м!',	5,	1,	'2011-09-23 06:02:04',	'0000-00-00 00:00:00'),
(87,	42,	55,	'Екатерина',	'Сегодня заказывала первый раз. Приятно удивлена!\r\nОбещали привезти через 1,5 часа. А привезли через 40 мин. Очень вкусно. Спасибо!',	5,	1,	'2011-11-11 13:35:12',	'0000-00-00 00:00:00'),
(70,	42,	0,	'Алла',	'очень вкусно,быстро доставили,цена супер))))\r\nспасибо за Вашу работу))))',	5,	1,	'2011-05-12 05:24:48',	'0000-00-00 00:00:00'),
(71,	87,	0,	'Еленка',	'Было незабываемо вкусно, хочу еще!)))\r\nЛучшие суши! Я теперь у вас постоянный клиент!',	5,	1,	'2011-05-12 05:25:31',	'0000-00-00 00:00:00'),
(72,	87,	0,	'Еленка',	'Суши просто объедение....честно съела бы еще парочку таких же!)))\r\nЯ теперь ваш постоянный клиент!))))',	5,	1,	'2011-05-12 05:25:10',	'0000-00-00 00:00:00'),
(73,	42,	0,	'Пэн',	'Очень понравилось , доставка в течении 30-40 минут. Спасибо !',	5,	1,	'2011-06-05 11:43:36',	'0000-00-00 00:00:00'),
(92,	90,	0,	'лариса',	'Спасибо большое.Очень вкусно,все остались довольны-)))',	5,	1,	'2012-01-16 12:38:03',	'0000-00-00 00:00:00'),
(75,	42,	0,	'Лена',	'ооочень вкусно. и быстрая доставка) СПАСИБО!',	5,	1,	'2011-06-17 07:22:01',	'0000-00-00 00:00:00'),
(93,	155,	0,	'Илья',	'Очень вкусно с пшеничной лапшой 8))',	5,	1,	'2012-01-20 03:08:59',	'0000-00-00 00:00:00'),
(77,	59,	0,	'Лена',	'вкусно. доставлен был очень горячим- что ценно) спасибо!',	5,	1,	'2011-06-17 07:23:28',	'0000-00-00 00:00:00'),
(78,	57,	0,	'Аня',	'Вкусняшка,просто пальчики оближешь.......... :D',	5,	1,	'2011-06-17 07:23:57',	'0000-00-00 00:00:00'),
(94,	121,	0,	'Рита',	'объедение просто!! заказывайте не пожалеете!! спасибо ЕвроСуши!!!',	5,	1,	'2012-02-08 03:00:58',	'0000-00-00 00:00:00'),
(80,	85,	0,	'СЕРГЕЙ',	'заказываю первый раз когда попробую дам отзыв',	5,	1,	'2011-07-19 08:40:45',	'0000-00-00 00:00:00'),
(88,	139,	57,	'Наталья',	'Ням,ням)))Очень было вкусно)',	5,	1,	'2011-11-21 02:11:51',	'0000-00-00 00:00:00'),
(89,	35,	0,	'Екатерина',	'Обалденный ролл!!мы теперь ваши постоянные клиенты))) Спасибо!',	5,	1,	'2011-11-28 02:00:12',	'0000-00-00 00:00:00'),
(96,	35,	0,	'Илья Пэн',	'Просто бомба . Других слов не подобрать !!!',	5,	1,	'2012-02-17 02:11:56',	'0000-00-00 00:00:00'),
(97,	68,	0,	'Елена',	'В Евросуши сaaaaaaaaaaамые вкусные',	5,	1,	'2012-11-09 00:41:21',	'0000-00-00 00:00:00'),
(100,	136,	149,	'Анна',	'Специально зашла написать,что у вас самые вкусные запеченные роллы! Пол года собиралась это сделать, да вот руки дошли))',	5,	0,	'2012-11-20 11:58:16',	'0000-00-00 00:00:00'),
(101,	83,	0,	'Елена',	'Сидела на сайте, выбирала, выбирала, всё определилась, а заказать не получилось, потому что глюк с сайтом: &quot;запрашиваемая страница не найдена&quot; и контактов на сайте нет...капец. Ваши айтишники просто МАЛАДЦЫ!',	1,	0,	'2012-12-29 12:09:02',	'0000-00-00 00:00:00'),
(102,	154,	0,	'Вячеслав',	'С фунчезой в коробочке, м-м-м, не один раз уже заказывал. ',	5,	0,	'2013-01-13 05:39:24',	'0000-00-00 00:00:00'),
(103,	35,	0,	'Анна',	'Лучшие из лучших!!!!!!!!!!!!!!',	5,	0,	'2013-01-19 03:55:48',	'0000-00-00 00:00:00'),
(104,	139,	0,	'Жанна',	'Это самая вкусная доставка суши в СПб и эти роллы самые вкусные на Свете!!!',	5,	0,	'2013-01-29 11:10:58',	'0000-00-00 00:00:00'),
(105,	158,	0,	'Анна',	'омномном очень вкусный набор и не так уж дорого',	5,	0,	'2013-05-02 14:09:46',	'0000-00-00 00:00:00');
